def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    urgency_scores = []
    for idx, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_distance(cur_truck_pos, customer_pos) / truck_speed
        arrival_time = current_time + travel_time
        start_window, end_window = time_windows[idx]

        if arrival_time > end_window:
            urgency = (arrival_time - end_window) ** 2  # squared penalty for urgency
        elif arrival_time < start_window:
            urgency = (start_window - arrival_time)  # consider waiting as less urgent
        else:
            urgency = -1  # if within time window, add bonus for urgency

        urgency += travel_time # Include travel time to emphasize closer locations
        urgency_scores.append(urgency)

    # Comparing with other trucks' potential to serve customers might change priority
    for idx, other_truck_pos in enumerate(all_truck_pos):
        if np.array_equal(other_truck_pos, cur_truck_pos):
            continue  # Skip the current truck

        for cust_idx, customer_pos in enumerate(unvisited_customers):
            other_travel_time = calculate_distance(other_truck_pos, customer_pos) / truck_speed
            other_arrival_time = current_time + other_travel_time
            if other_arrival_time < arrival_time:
                urgency_scores[cust_idx] *= 1.1  # if other truck can get there sooner, increase urgency of current choice

    best_node = np.argmin(urgency_scores)  # Choose the customer with the highest urgency
